"use client";

import React, { useState, useEffect, useRef, useCallback } from "react";
import Image from "next/image";


import Particles from "@/assets/svgs/turn-birthday-into-moment-particles.svg";
import GlobalButton from "../buttons/GlobalButton";

const cardData = [
  {
    title: "Campaign for Kim Kardashian!",
    birthday: "Birthday on Jun 4",
    followers: "1.4M",
    participated: "1.1M",
    wishes: "13000",
    gifts: "10000"
  },
  {
    title: "Support Maria's Mission!",
    birthday: "Birthday on Aug 15",
    followers: "890K",
    participated: "650K",
    wishes: "8900",
    gifts: "7200"
  },
  {
    title: "Join Farah's Cause!",
    birthday: "Birthday on Sep 22",
    followers: "2.1M",
    participated: "1.8M",
    wishes: "21000",
    gifts: "18500"
  }
];

const StartYourFirstCelebration = () => {
  const [activeCardIndex, setActiveCardIndex] = useState(0);
  const [visibleCards, setVisibleCards] = useState<number[]>([]);
  const sectionRef = useRef<HTMLDivElement>(null);

  const animateCardsSequentially = useCallback(() => {
    setVisibleCards([]);
    cardData.forEach((_, index) => {
      setTimeout(() => {
        setVisibleCards(prev => [...prev, index]);
      }, index * 300); // 300ms delay between each card
    });
  }, []);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          animateCardsSequentially();
        }
      },
      { threshold: 0.3 }
    );

    if (sectionRef.current) {
      observer.observe(sectionRef.current);
    }

    return () => observer.disconnect();
  }, [animateCardsSequentially]);

  const handleDotClick = (index: number) => {
    setActiveCardIndex(index);
  };

  return (
    <section ref={sectionRef} className="relative px-[5%] max-[769px]:px-4 py-10">
      <div className={`relative rounded-[20px] bg-gradient-to-b from-pink-500 via-pink-400 to-purple-500 text-white text-center px-6 py-12 overflow-hidden`}>

        <Image
          src={Particles}
          alt="Confetti Particles"
          className="absolute inset-0 w-full h-full object-cover pointer-events-none"
        />

        <h2 className="text-[30px] max-[600px]:text-[24px] font-bold mb-4">
          Turn Your Birthday Into a Movement.
        </h2>

        <p className="max-w-3xl mx-auto text-[16px] leading-relaxed mb-6">
          Are you a creator, public figure, community leader or just someone passionate about making a difference?
          This year, let your birthday do more. <span className="font-semibold">Start a Spotlight Board</span> to raise awareness,
          support a cause, or rally your community. It&apos;s public, purpose-driven, and made to inspire.
          Anyone can join in by sending wishes, sharing your story, or contributing a gift toward your mission.
          Your celebration becomes a platform for impact.
        </p>

        <p className="font-semibold text-lg mb-8">
          🎂 Because some birthdays aren&apos;t just about cake they&apos;re about change.
        </p>

        <div className="flex flex-wrap justify-center gap-4 mb-16">
          <GlobalButton title="Explore Spotlight Birthdays" bgColor="white" color="#000000" width="220px" hover={{ bgColor: 'white' }} />
          <GlobalButton title="Create a Public Birthday Board" bgColor="transparent" borderColor="white" borderWidth="1px" width="220px" hover={{ bgColor: 'transparent' }} />
        </div>
      </div>
    </section>
  );
};

export default StartYourFirstCelebration;